fibonacci:
# Function to calculate the Nth Fibonacci number (0-indexed) iteratively
fibonacci <- function(n) {
  if (!is.numeric(n) || n < 0 || floor(n) != n) {
    stop("Input must be a non-negative integer.")
  }
  if (n == 0) return(0)
  if (n == 1) return(1)

  # Use numeric type which is typically double precision in R
  # Can handle fairly large integers accurately up to 2^53
  a <- 0
  b <- 1
  for (i in 2:n) {
    # Stop if numbers get too large for standard double precision representation
    # if (b > .Machine$double.xmax / 2) { # Basic overflow check concept
    #    warning("Fibonacci number getting too large for standard numeric type.")
    #    break
    # }
    next_val <- a + b
    a <- b
    b <- next_val
  }
  return(b)
  # For arbitrarily large integers, package 'gmp' provides BigInt support.
}

# Function to generate first 'count' Fibonacci numbers
generate_fib_sequence <- function(count) {
   if (!is.numeric(count) || count < 0 || floor(count) != count) {
    stop("Count must be a non-negative integer.")
   }
   # Use sapply to apply the fibonacci function to the sequence 0 to count-1
   sapply(0:(count-1), fibonacci)
}

# Example Usage
n <- 10
print(paste0("Fibonacci number F(", n, "): ", fibonacci(n))) # paste0 concatenates without space

num_terms <- 15
print(paste("First", num_terms, "Fibonacci numbers:"))
print(generate_fib_sequence(num_terms))

