primeCheck:
# Function to check if a number is prime

is_prime <- function(n) {
  # Input validation
  if (!is.numeric(n) || length(n) != 1 || floor(n) != n) {
    warning("Input must be a single integer.")
    return(FALSE)
  }

  if (n <= 1) return(FALSE)
  if (n <= 3) return(TRUE)
  if (n %% 2 == 0 || n %% 3 == 0) return(FALSE) # Use %% for modulo

  # Check divisors from 5 upwards, stepping by 6
  i <- 5
  # Calculate integer square root limit
  limit <- floor(sqrt(n))

  while (i <= limit) {
    if (n %% i == 0 || n %% (i + 2) == 0) {
      return(FALSE) # Divisor found
    }
    i <- i + 6
  }
  return(TRUE) # No divisors found
}

# Example usage
numbers_to_check <- c(2, 3, 4, 17, 25, 29, 97, 100, 1, -5)

for (n in numbers_to_check) {
  # Need to handle non-integer values passed to is_prime if vector contains them
  if (is_prime(n)) {
    print(paste(n, "is prime."))
  } else {
    print(paste(n, "is not prime."))
  }
}

