readFile:
# Read content from a file

# Specify the path to the file
file_path <- "r_read_test.txt"

# Create a dummy file for reading using writeLines
# sink() or cat() could also be used.
lines_to_write <- c("Line 1 content from R.", "This is the second line.", "End.")
tryCatch({
  con <- file(file_path, "w") # Open connection in write mode
  writeLines(lines_to_write, con)
  close(con)
  print(paste("Created dummy file '", file_path, "' for reading.", sep=""))
}, error = function(e) {
  print(paste("Error creating dummy file:", e$message))
  # Ensure connection is closed if opened
  if (exists("con") && isOpen(con)) { close(con) }
})


print(paste("--- Reading file '", file_path, "' using readLines ---", sep=""))

if (file.exists(file_path)) {
  tryCatch({
    # readLines reads the file into a character vector, one element per line
    file_content_lines <- readLines(file_path)
    print(paste("Read", length(file_content_lines), "lines:"))

    # Print the vector
    print(file_content_lines)

    print("--- Processing line by line ---")
    line_num <- 1
    for (line in file_content_lines) {
      print(paste("Line", line_num, ":", line))
      line_num <- line_num + 1
    }

  }, error = function(e) {
      print(paste("Error reading file:", e$message))
  })

} else {
  print(paste("Error: File not found '", file_path, "'", sep=""))
}

# Clean up dummy file
if (file.exists(file_path)) {
  file.remove(file_path)
  print(paste("\nCleaned up dummy file '", file_path, "'.", sep=""))
}

writeFile:
# Write or append text content to a file

file_path <- "output_r.txt"
initial_lines <- c("First line written by R.", "Second line using writeLines.")
lines_to_append <- c("Third line, appended.", "Fourth line.")

# --- Write using writeLines (overwrites or creates) ---
print(paste("--- Writing to '", file_path, "' (overwrite) ---", sep=""))
tryCatch({
  con <- file(file_path, "w") # Open connection in write mode
  writeLines(initial_lines, con) # Writes character vector, adds newlines
  close(con)
  print(paste("Successfully wrote", length(initial_lines), "lines."))
  # For single string: cat("Single string", file = file_path)
}, error = function(e) {
  print(paste("Error writing to file:", e$message))
  if (exists("con") && isOpen(con)) { close(con) }
})

# --- Append using writeLines with 'append' mode or cat(..., append=TRUE) ---
print(paste("\n--- Appending to '", file_path, "' ---", sep=""))
tryCatch({
  # Option 1: Use cat with append = TRUE
  cat(lines_to_append, file = file_path, sep = "\n", append = TRUE)
  # Add final newline if needed explicitly
  cat("\n", file = file_path, append = TRUE)

  # Option 2: Use writeLines with open="a" (append mode)
  # con_append <- file(file_path, open="a")
  # writeLines(lines_to_append, con_append)
  # close(con_append)

  print(paste("Successfully appended", length(lines_to_append), "lines."))
}, error = function(e) {
  print(paste("Error appending to file:", e$message))
  # if (exists("con_append") && isOpen(con_append)) { close(con_append) }
})


# --- Display final content ---
print(paste("\n--- Final content of '", file_path, "': ---", sep=""))
if (file.exists(file_path)) {
  tryCatch({
    # Read and print line by line
    readLines(file_path) |> print() # Using base pipe |> (R 4.1+)
    # Or: print(readLines(file_path))
  }, error = function(e) {
    print(paste("Error reading back file:", e$message))
  })
} else {
  print(paste("File '", file_path, "' not found for display.", sep=""))
}

